public sealed class ResearchSourceRegistryService
{
    private static readonly HashSet<string> AllowedExtensions = new(StringComparer.OrdinalIgnoreCase) { ".csv", ".tsv", ".txt", ".json" };
    public ResearchSourceRegistration Register(string importRoot, string suppliedPath, string sourceCode, ResearchSourceType type, string authority, string dataset, string officialReference, string schemaVersion, bool synthetic, string actor, DateTime atUtc)
    {
        var root = Path.GetFullPath(importRoot); var path = Path.GetFullPath(suppliedPath); if (!path.StartsWith(root + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase)) throw new ArgumentException("Source path traversal or path outside configured import root is prohibited."); if (!File.Exists(path)) throw new FileNotFoundException("Locally supplied research source does not exist.", Path.GetFileName(path)); if (!AllowedExtensions.Contains(Path.GetExtension(path))) throw new InvalidOperationException("Research source extension is unsupported."); var bytes = File.ReadAllBytes(path); var encoding = DetectEncoding(bytes); return new(sourceCode, type, authority, dataset, "Locally supplied research source; contents are never logged.", officialReference, atUtc, null, null, "Review source-specific license and usage terms.", schemaVersion, Path.GetFileName(path), Path.GetRelativePath(root, path), Convert.ToHexString(SHA256.HashData(bytes)), bytes.LongLength, encoding, Path.GetExtension(path).Equals(".tsv", StringComparison.OrdinalIgnoreCase) ? "TAB" : ",", synthetic, actor, atUtc);
    }
    public void ValidateUnmodified(ResearchSourceRegistration registration, string importRoot) { var path = Path.GetFullPath(Path.Combine(importRoot, registration.RegisteredPath)); if (!File.Exists(path) || Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(path))) != registration.Sha256) throw new InvalidOperationException("Registered source file is missing or its SHA-256 changed; create a new registration."); }
    public static void RejectDuplicates(IEnumerable<ResearchSourceRegistration> registrations) { var duplicate = registrations.GroupBy(x => x.SourceCode, StringComparer.Ordinal).FirstOrDefault(x => x.Count() > 1); if (duplicate is not null) throw new InvalidOperationException($"Duplicate source registration under freeze: {duplicate.Key}."); }
    private static string DetectEncoding(byte[] bytes) => bytes.Length >= 3 && bytes[0] == 0xEF && bytes[1] == 0xBB && bytes[2] == 0xBF ? "utf-8-bom" : "utf-8";
}

public sealed class ResearchFreezeQualityGate
{
    public static readonly string[] RequiredGateCodes = ["SourceHashMatches", "SourceSchemaMatches", "NoDuplicateSourceRegistration", "DatasetValidated", "FeatureSetValidated", "NoDuplicateAnalyticalKey", "ValidCalendarQuarter", "NoUnapprovedPreLaunchObservation", "NonnegativePrescription", "ValidReimbursement", "StateCodeResolved", "StateDenominatorReproducible", "MissingDistinctFromZero", "SuppressedDistinctFromZero", "Q4CompleteFollowup", "CensoredLabelsNull", "NoProhibitedFeature", "NoBlockingLeakage", "HistoricalMarketWeightWindow", "NoPredictiveGroupOverlap", "ChronologicalPredictiveSplit", "TreatmentPrecedesOutcome", "AdjustmentAvailability", "ValidTreatmentOutcome", "TreatedAndControlPresent", "PythonLockMatches", "ValidationContractSupported", "RequiredDocumentationExists", "GitDataSafety", "NoSecretsInManifest"];
    private static readonly HashSet<string> ProhibitedFeatures = new(StringComparer.OrdinalIgnoreCase) { "LabelNextQuarterEntry", "LabelFutureQ4NumericDistribution", "LabelFutureQ4WeightedDistribution", "LabelFutureQ4AccessGap", "OutcomeValue" };
    public IReadOnlyList<ResearchFreezeFinding> Evaluate(IReadOnlyList<ResearchObservation> rows, bool sourceHashMatches = true, bool sourceSchemaMatches = true, bool duplicateSource = false, bool datasetValidated = true, bool featureValidated = true, bool stateDenominatorReproducible = true, bool marketWeightWindowValid = true, bool pythonLockMatches = true, bool contractSupported = true, bool documentationExists = true, bool gitSafe = true, bool secretsSafe = true, bool splitOverlap = false, bool chronologicalSplit = true)
    {
        var f = new List<ResearchFreezeFinding>(); void Check(bool ok, string code, string description, ResearchFindingSeverity severity = ResearchFindingSeverity.Blocking) { if (!ok) f.Add(new(code, severity, description, "Correct the input or create a new version before approval.")); }
        Check(sourceHashMatches, "SourceHashMatches", "A source hash differs from registration."); Check(sourceSchemaMatches, "SourceSchemaMatches", "A source schema differs from its approved profile."); Check(!duplicateSource, "NoDuplicateSourceRegistration", "Duplicate source registration exists."); Check(datasetValidated, "DatasetValidated", "DatasetVersion is not validated."); Check(featureValidated, "FeatureSetValidated", "FeatureSetVersion is not validated."); Check(rows.GroupBy(x => x.AnalyticalKey).All(x => x.Count() == 1), "NoDuplicateAnalyticalKey", "Duplicate analytical key exists."); Check(rows.All(x => Quarter(x.QuarterId)), "ValidCalendarQuarter", "Invalid calendar quarter exists."); Check(rows.All(x => x.QuarterId >= x.ApprovalQuarterId), "NoUnapprovedPreLaunchObservation", "Pre-approval observation is not explicitly allowed."); Check(rows.All(x => x.PrescriptionCount is null or >= 0), "NonnegativePrescription", "Negative prescription value exists."); Check(rows.All(x => x.Reimbursement is null || x.Reimbursement >= 0), "ValidReimbursement", "Negative reimbursement requires a separately approved policy."); Check(rows.All(x => x.StateCode.Length == 2 && x.StateCode.All(char.IsLetter)), "StateCodeResolved", "Unresolved state code exists."); Check(stateDenominatorReproducible, "StateDenominatorReproducible", "State eligibility denominator is not reproducible."); Check(rows.All(x => !(x.IsMissing && x.PrescriptionCount == 0)), "MissingDistinctFromZero", "Missing observation was encoded as zero."); Check(rows.All(x => !(x.IsSuppressed && x.PrescriptionCount == 0)), "SuppressedDistinctFromZero", "Suppressed observation was encoded as zero."); Check(rows.All(x => x.Q4Complete != false || x.NextQuarterLabel is null), "Q4CompleteFollowup", "Incomplete Q4 follow-up has a populated outcome."); Check(rows.All(x => x.Q4Complete != false || x.NextQuarterLabel is null), "CensoredLabelsNull", "Censored label is not null."); Check(rows.All(x => !x.SelectedFeatures.Intersect(ProhibitedFeatures, StringComparer.OrdinalIgnoreCase).Any()), "NoProhibitedFeature", "A prohibited label/future feature is selected."); Check(rows.All(x => !x.HasBlockingLeakage), "NoBlockingLeakage", "Blocking leakage finding exists."); Check(marketWeightWindowValid, "HistoricalMarketWeightWindow", "Market-weight reference uses an undeclared or future window."); Check(!splitOverlap, "NoPredictiveGroupOverlap", "GenericLaunchId occurs in multiple partitions."); Check(chronologicalSplit, "ChronologicalPredictiveSplit", "Predictive split is not chronological."); Check(rows.All(x => x.TreatmentQuarterId < x.OutcomeQuarterId), "TreatmentPrecedesOutcome", "Treatment does not precede outcome."); Check(rows.All(x => x.BaselineQuarterId <= x.TreatmentQuarterId), "AdjustmentAvailability", "Adjustment value is post-treatment."); Check(rows.All(x => x.Treatment.HasValue && x.NextQuarterLabel.HasValue), "ValidTreatmentOutcome", "Treatment/outcome domain is unavailable for an included causal row."); Check(rows.Any(x => x.Treatment == true) && rows.Any(x => x.Treatment == false), "TreatedAndControlPresent", "Both treatment classes are required."); Check(pythonLockMatches, "PythonLockMatches", "Python environment differs from lock."); Check(contractSupported, "ValidationContractSupported", "C#/Python validation contract is unsupported."); Check(documentationExists, "RequiredDocumentationExists", "Required pre-analysis documentation is missing."); Check(gitSafe, "GitDataSafety", "Potential real-data or secret artifact is tracked/staged."); Check(secretsSafe, "NoSecretsInManifest", "Research manifest contains a secret-pattern key."); return f;
    }
    private static bool Quarter(int q) => q > 0 && q % 10 is >= 1 and <= 4;
}

public sealed class ResearchProfilingService
{
    public ResearchDatasetProfile Profile(IReadOnlyList<ResearchObservation> rows, int sourceRows, int rejectedRows)
    {
        if (rows.Count == 0) throw new InvalidOperationException("Profiling requires rows."); static decimal Median(IEnumerable<decimal> x) { var a = x.Order().ToArray(); return a.Length == 0 ? 0 : a[a.Length / 2]; }
        var p = rows.Where(x => x.PrescriptionCount.HasValue).Select(x => (decimal)x.PrescriptionCount!.Value).ToArray(); var r = rows.Where(x => x.Reimbursement.HasValue).Select(x => x.Reimbursement!.Value).ToArray(); var treated = rows.Count(x => x.Treatment == true); var control = rows.Count(x => x.Treatment == false); return new(sourceRows, rows.Count, rejectedRows, rows.Select(x => x.DrugId).Distinct().Count(), rows.Select(x => x.GenericLaunchId).Distinct().Count(), rows.Select(x => x.StateCode).Distinct().Count(), rows.Min(x => x.QuarterId), rows.Max(x => x.QuarterId), rows.Count, rows.Select(x => new { x.GenericLaunchId, x.QuarterId }).Distinct().Count(), rows.Count - rows.Select(x => x.AnalyticalKey).Distinct().Count(), new Dictionary<string, int> { { "PrescriptionCount", rows.Count(x => !x.PrescriptionCount.HasValue) }, { "Reimbursement", rows.Count(x => !x.Reimbursement.HasValue) } }, rows.Count(x => x.IsSuppressed), rows.Count(x => x.PrescriptionCount == 0 && !x.IsMissing && !x.IsSuppressed), p.DefaultIfEmpty().Min(), Median(p), p.DefaultIfEmpty().Max(), r.DefaultIfEmpty().Min(), Median(r), r.DefaultIfEmpty().Max(), rows.GroupBy(x => x.ApprovalQuarterId / 10).ToDictionary(x => x.Key, x => x.Select(y => y.GenericLaunchId).Distinct().Count()), rows.GroupBy(x => x.StateCode).ToDictionary(x => x.Key, x => x.Count(y => !y.IsMissing) / (double)x.Count()), rows.GroupBy(x => x.QuarterId).ToDictionary(x => x.Key, x => x.Count()), rows.Where(x => x.Q4Complete == true).Select(x => x.GenericLaunchId).Distinct().Count(), rows.Where(x => x.Q4Complete == false).Select(x => x.GenericLaunchId).Distinct().Count(), rows.Count(x => x.NextQuarterLabel.HasValue), rows.Count(x => x.NextQuarterLabel == true), rows.Count(x => x.NextQuarterLabel == false), treated + control == 0 ? 0 : treated / (double)(treated + control), treated, control, treated > 0 && control > 0 ? .1 : null, treated > 0 && control > 0 ? .9 : null, ResearchFreezePackageWriter.Notice);
    }
}

public sealed class ResearchCohortService
{
    public CohortFreezeResult Build(IReadOnlyList<ResearchObservation> rows, string ruleVersion)
    { var included = new List<long>(); var excluded = new Dictionary<long, string>(); foreach (var x in rows.OrderBy(x => x.AnalyticalKey)) { var reason = x.StateCode.Length != 2 ? "InvalidState" : x.QuarterId < x.ApprovalQuarterId ? "BeforeLaunchReference" : x.IsMissing ? "MissingStateQuarter" : x.IsSuppressed ? "SuppressedUnknown" : x.NextQuarterLabel is null ? "CensoredOrMissingOutcome" : x.HasBlockingLeakage ? "BlockingLeakage" : null; if (reason is null) included.Add(x.AnalyticalKey); else excluded[x.AnalyticalKey] = reason; } var counts = excluded.Values.GroupBy(x => x).ToDictionary(x => x.Key, x => x.Count()); var canonical = JsonSerializer.Serialize(new { ruleVersion, included, excluded = excluded.OrderBy(x => x.Key) }); return new(included, excluded, counts, Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(canonical)))); }
}

public sealed class ResearchGitSafetyService
{
    private static readonly string[] UnsafeExtensions = [".bak", ".mdf", ".ldf", ".sqlite", ".db", ".zip", ".parquet", ".onnx", ".model"];
    public IReadOnlyList<string> FindUnsafeTrackedPaths(string repositoryRoot, IEnumerable<string>? trackedPaths = null) { var paths = trackedPaths ?? GitTracked(repositoryRoot); return paths.Where(p => p.Contains("data/raw", StringComparison.OrdinalIgnoreCase) || p.Contains(".venv", StringComparison.OrdinalIgnoreCase) || Path.GetFileName(p).StartsWith(".env", StringComparison.OrdinalIgnoreCase) || UnsafeExtensions.Contains(Path.GetExtension(p), StringComparer.OrdinalIgnoreCase) || (Path.GetExtension(p).Equals(".csv", StringComparison.OrdinalIgnoreCase) && !p.StartsWith("samples/data/feature/synthetic_", StringComparison.OrdinalIgnoreCase))).Order().ToArray(); }
    private static IEnumerable<string> GitTracked(string root) { var psi = new ProcessStartInfo("git", "ls-files --cached --others --exclude-standard") { WorkingDirectory = root, RedirectStandardOutput = true, UseShellExecute = false, CreateNoWindow = true }; using var p = Process.Start(psi) ?? throw new InvalidOperationException("Unable to inspect Git paths."); var output = p.StandardOutput.ReadToEnd(); p.WaitForExit(); return output.Split(['\r', '\n'], StringSplitOptions.RemoveEmptyEntries); }
}

public sealed class ResearchFreezePackageWriter
{
    public const string Notice = "Synthetic development data — not research results.";
    public static readonly string[] RequiredFiles = ["research_protocol.json", "research_protocol.md", "source_manifest.json", "source_hashes.json", "dataset_profile.json", "dataset_profile.md", "cohort_definition.json", "cohort_manifest.json", "exclusion_summary.json", "feature_manifest.json", "predictive_protocol.json", "predictive_split_manifest.json", "causal_protocol.json", "dag.json", "adjustment_set.json", "treatment_definition.json", "outcome_definition.json", "environment_manifest.json", "python_requirements.lock", "dotnet_packages.json", "validation_summary.json", "validation_summary.md", "freeze_manifest.json"];
    public SyntheticResearchFreezeResult Write(string artifactRoot, string freezeCode, ResearchProtocol protocol, ResearchDataFreeze freeze, IReadOnlyList<ResearchSourceRegistration> sources, ResearchDatasetProfile profile, CohortFreezeResult cohort, IReadOnlyList<ResearchFreezeFinding> findings, string pythonLock, string dotnetPackages)
    {
        var proposedRoot = SafeRoot(artifactRoot, freezeCode);
        if (Directory.Exists(proposedRoot))
            throw new InvalidOperationException("A freeze package with this code already exists; frozen packages are immutable. Use a new freeze code.");
        var root = SafeRoot(artifactRoot, freezeCode); if (Directory.Exists(root)) Directory.Delete(root, true); Directory.CreateDirectory(root); var lineage = new { freezeCode, protocolVersion = protocol.ProtocolVersion, datasetVersion = freeze.DatasetVersionId, featureSetVersion = freeze.FeatureSetVersionId, gitCommit = freeze.GitCommitHash, generationTimestamp = "declared-operational", sourceHashes = sources.ToDictionary(x => x.SourceCode, x => x.Sha256), definitionHashes = new { protocol = protocol.DefinitionHash, cohort = freeze.CohortHash, feature = freeze.FeatureSchemaHash, predictive = freeze.PredictiveSplitHash, causal = freeze.CausalProtocolHash }, reproducibilityHash = freeze.ReproducibilityHash(), notice = Notice }; var payloads = new Dictionary<string, object> { ["research_protocol.json"] = new { lineage, protocol }, ["source_manifest.json"] = new { lineage, sources }, ["source_hashes.json"] = new { lineage, hashes = sources.ToDictionary(x => x.SourceCode, x => x.Sha256) }, ["dataset_profile.json"] = new { lineage, profile }, ["cohort_definition.json"] = new { lineage, version = "cohort-v1", population = "Generic launch × state × quarter", minimumFollowup = "next quarter; Q4 only when complete", launchReference = "FDA approval proxy", eligibleStatePolicy = "state-eligibility-v1", entryPolicy = "any-positive-v1", mappingPolicy = "validated-normalized-identity-v1", suppressionPolicy = "unknown-not-zero", missingDataPolicy = "explicit", duplicatePolicy = "blocking", exclusionHierarchy = cohort.Counts.Keys.Order().ToArray() }, ["cohort_manifest.json"] = new { lineage, cohort }, ["exclusion_summary.json"] = new { lineage, cohort.Counts }, ["feature_manifest.json"] = new { lineage, version = "next-entry-features-v1", prohibited = new[] { "labels", "future outcomes", "post-treatment values" } }, ["predictive_protocol.json"] = new { lineage, task = "NextQuarterStateEntry", label = "next observable quarter first entry", models = new[] { "PrevalenceBaseline", "HistoricalStateRateBaseline", "SdcaLogisticRegression", "FastTree", "FastForest", "LightGbm" }, groupingKey = "GenericLaunchId", primaryMetric = "PR_AUC", secondaryMetrics = new[] { "LogLoss", "Brier", "Recall", "RocAuc" }, thresholdPolicy = "validation-only", calibration = "validation-only Platt", subgroups = "prespecified with suppression", tieBreaker = "LogLoss,Brier,Simplicity", testSetUsage = "single frozen evaluation after selection", randomSeed = 17, maximumConfigurations = 8, testPartitionLockedForSelection = true }, ["predictive_split_manifest.json"] = new { lineage, version = "temporal-grouped-v1", groupingKey = "GenericLaunchId", chronological = true, testPartitionLockedForSelection = true, hash = freeze.PredictiveSplitHash }, ["causal_protocol.json"] = new { lineage, treatment = "HighNeighborAdoptionExposure", continuousExposure = "eligible peer adoption share", threshold = .5, outcome = "NextQuarterEntry", timeZero = "observation quarter start", estimand = "ATT", effectScale = "RiskDifference", primaryEstimator = "AIPW", secondaryEstimators = new[] { "Unadjusted", "IPTW", "OutcomeRegression" }, dagVersion = "peer-exposure-dag-v1", adjustmentSet = "peer-exposure-adjustment-v1", missingData = "complete case development policy", propensity = "logistic; outcome prohibited", clipping = "[0.02,0.98] sensitivity", overlap = "empirical common support", balance = "absolute SMD <= 0.1 diagnostic", bootstrap = "GenericLaunchId clustered", placebos = new[] { "future treatment", "pretreatment outcome", "permutation" }, partialInterference = "explicit limitation", unmeasuredConfounding = "explicit limitation; no proof" }, ["dag.json"] = new { lineage, version = "peer-exposure-dag-v1", status = "human-authored assumption" }, ["adjustment_set.json"] = new { lineage, version = "peer-exposure-adjustment-v1", availability = "pretreatment only" }, ["treatment_definition.json"] = new { lineage, version = "neighbor-v1", threshold = .5, outcomeBlindSelection = true }, ["outcome_definition.json"] = new { lineage, version = "next-entry-v1", censoredLabels = "null" }, ["environment_manifest.json"] = new { lineage, operatingSystem = Environment.OSVersion.VersionString, dotnet = Environment.Version.ToString(), targetFramework = "net10.0", python = "3.12.10", pythonLockHash = freeze.PythonEnvironmentHash, dowhy = "locked", econml = "locked", pandas = "locked", numpy = "locked", scikitLearn = "locked", mlnet = "5.0.0", databaseProvider = "EF Core SQL Server 10.0.10", repositoryDirty = true }, ["dotnet_packages.json"] = new { lineage, packages = dotnetPackages }, ["validation_summary.json"] = new { lineage, blocking = findings.Count(x => x.Severity == ResearchFindingSeverity.Blocking), warnings = findings.Count(x => x.Severity == ResearchFindingSeverity.Warning), findings }, ["freeze_manifest.json"] = new { lineage, freeze.Status, freeze.IsSynthetic, freeze.BlockingFindingCount, freeze.WarningCount } };
        foreach (var (name, value) in payloads) File.WriteAllText(Path.Combine(root, name), JsonSerializer.Serialize(value, new JsonSerializerOptions { WriteIndented = true }), new UTF8Encoding(false)); File.WriteAllText(Path.Combine(root, "python_requirements.lock"), pythonLock, new UTF8Encoding(false)); File.WriteAllText(Path.Combine(root, "research_protocol.md"), $"# Research protocol\n\n> **{Notice}**\n\n{protocol.Title}\n", new UTF8Encoding(false)); File.WriteAllText(Path.Combine(root, "dataset_profile.md"), $"# Dataset profile\n\n> **{Notice}**\n\nDescriptive software validation only; no scientific conclusion.\n", new UTF8Encoding(false)); File.WriteAllText(Path.Combine(root, "validation_summary.md"), $"# Validation summary\n\n> **{Notice}**\n\nBlocking findings: {findings.Count(x => x.Severity == ResearchFindingSeverity.Blocking)}.\n", new UTF8Encoding(false)); var hashes = RequiredFiles.ToDictionary(x => x, x => Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(Path.Combine(root, x))))); var reproducibility = Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(string.Join('\n', hashes.OrderBy(x => x.Key).Select(x => $"{x.Key}:{x.Value}"))))); File.WriteAllText(Path.Combine(root, "file_hashes.json"), JsonSerializer.Serialize(new { freezeCode, files = hashes, reproducibilityHash = reproducibility, notice = Notice }, new JsonSerializerOptions { WriteIndented = true }), new UTF8Encoding(false)); return new(freezeCode, root, reproducibility, freeze.BlockingFindingCount, freeze.WarningCount, freeze.Status, RequiredFiles.Append("file_hashes.json").ToArray());
    }
    public void Verify(string root) { using var doc = JsonDocument.Parse(File.ReadAllText(Path.Combine(root, "file_hashes.json"))); foreach (var item in doc.RootElement.GetProperty("files").EnumerateObject()) { var actual = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(Path.Combine(root, item.Name)))); if (actual != item.Value.GetString()) throw new InvalidOperationException($"Freeze artifact hash mismatch: {item.Name}."); } }
    private static string SafeRoot(string configured, string code) { if (string.IsNullOrWhiteSpace(code) || code.Any(x => !char.IsLetterOrDigit(x) && x is not '-' and not '_')) throw new ArgumentException("Unsafe freeze code."); var root = Path.GetFullPath(configured); var target = Path.GetFullPath(Path.Combine(root, code)); if (!target.StartsWith(root + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase)) throw new ArgumentException("Freeze path traversal is prohibited."); return target; }
}

public sealed class SyntheticResearchFreezeWorkflow
{
    public SyntheticResearchFreezeResult Run(string artifactRoot, string freezeCode, string pythonLock, string dotnetPackages)
    {
        var at = new DateTime(2026, 7, 21, 0, 0, 0, DateTimeKind.Utc); var sha = (string value) => Convert.ToHexString(SHA256.HashData(Encoding.UTF8.GetBytes(value)));
        var protocol = new ResearchProtocol("approval-to-access", "1.0", "From Approval to Access: Predictive and Causal Analysis of Generic Drug Diffusion and State-Level Medicaid Access Inequality", "Can early information predict later access, and under stated observational assumptions what is the estimated peer-exposure effect?", "NextQuarterStateEntry", "What is the ATT risk difference of high peer-state exposure on next-quarter entry?", "PR_AUC", "LogLoss,Brier,Recall,RocAuc", "ATT", "RiskDifference", "AIPW", "IPTW,OutcomeRegression,Unadjusted", "Eligible generic launch × state × quarter observations", "Synthetic 2021-Q1 through 2022-Q4", "[{\"code\":\"ValidApprovalReference\"}]", "[{\"code\":\"CensoredOutcome\"}]", "state-eligibility-v1", "any-positive-v1", "historical-market-weight-v1", 1, 1, 1, 1, 1, 1, "CompleteCase", "Censored outcomes remain null", "Prespecified primary analysis; exploratory subgroups labeled", "Clipping, threshold, policy and placebo sensitivity", "Prespecified region, cohort and historical-volume groups with minimum support", "No outcome-driven protocol changes; new version required", at); protocol.SubmitForReview(); protocol.Approve("synthetic-reviewer", at.AddMinutes(1), "Synthetic development protocol approval for workflow verification only.");
        var sources = Enum.GetValues<ResearchSourceType>().Select((type, index) => new ResearchSourceRegistration($"synthetic-{type.ToString().ToLowerInvariant()}", type, "Synthetic fixture authority", "Synthetic fixture", "Synthetic source registration; no real records.", "local://synthetic-fixture", at, null, null, "Synthetic development use only.", "synthetic-schema-v1", $"synthetic-{index}.csv", $"synthetic/{index}.csv", sha($"source-{index}"), 100 + index, "utf-8", ",", true, "synthetic-builder", at)).ToArray(); foreach (var source in sources) source.MarkValidated(12, []);
        var rows = Enumerable.Range(0, 12).Select(i => new ResearchObservation(i + 1, 1 + i / 4, 1 + i / 4, $"S{(char)('A' + i % 4)}", 20211 + i % 4, 20211, 10 + i, 100m + i, false, false, i % 3 == 0, true, i % 2 == 0, 20210, 20211 + i % 4, 20212 + i % 4, false, ["QuarterSinceApproval", "StateHistoricalEntryRate"])).ToArray(); var profile = new ResearchProfilingService().Profile(rows, 12, 0); var cohort = new ResearchCohortService().Build(rows, "cohort-v1"); var pythonHash = sha(pythonLock); var dotnetHash = sha(dotnetPackages); var freeze = new ResearchDataFreeze(freezeCode, "1.0", 1, 1, 1, sha(string.Join('|', sources.Select(x => x.Sha256))), sha(JsonSerializer.Serialize(profile)), cohort.CohortHash, sha("next-entry-features-v1"), sha("temporal-grouped-v1"), sha("peer-causal-protocol-v1"), pythonHash, dotnetHash, "WORKTREE-NOT-COMMITTED", true, at, "Synthetic candidate only.");
        for (var next = ResearchFreezeStatus.SourceFilesRegistered; next <= ResearchFreezeStatus.ValidationBundleGenerated; next++) freeze.Advance(next);
        var blockingExample = new ResearchFreezeQualityGate().Evaluate(rows, sourceSchemaMatches: false); if (!blockingExample.Any(x => x.Severity == ResearchFindingSeverity.Blocking)) throw new InvalidOperationException("Synthetic blocking-gate example did not block."); var findings = new ResearchFreezeQualityGate().Evaluate(rows); freeze.RecordFindings(findings.Count(x => x.Severity == ResearchFindingSeverity.Blocking), findings.Count(x => x.Severity == ResearchFindingSeverity.Warning)); freeze.Approve(protocol, "synthetic-freeze-reviewer", at.AddMinutes(2), "Synthetic workflow gates passed; not a real-data approval."); var writer = new ResearchFreezePackageWriter(); return writer.Write(artifactRoot, freezeCode, protocol, freeze, sources, profile, cohort, findings, pythonLock, dotnetPackages);
    }
}
